import type * as Square from "../index";
export interface Measure {
    name: string;
    title?: string;
    shortTitle?: string;
    description?: string;
    type: string;
    aggType?: string;
    meta?: Record<string, unknown>;
    format?: Square.Format;
    formatDescription?: Square.FormatDescription;
    /** ISO 4217 currency code in uppercase (3 characters, e.g. USD, EUR) */
    currency?: string;
    /** When measure is defined in View, it keeps the original path: Cube.measure */
    aliasMember?: string;
}
